      "\u2014 PLAN A: \u0394\u0399\u0391\u03A3\u03A9\u039B\u0397\u039D\u03A9\u03A3\u0397 \u2014",
      "\u0392\u03B9\u03BD\u03C4\u03B5\u03BF\u03BB\u03B1\u03C1\u03C5\u03B3\u03B3\u03BF\u03C3\u03BA\u03CC\u03C0\u03B9\u03BF 1\u03B7\u03C2 \u03B3\u03C1\u03B1\u03BC\u03BC\u03AE\u03C2 (asleep)\xB7 \u03C0\u03BB\u03AE\u03C1\u03B7\u03C2 & \u03C0\u03C1\u03CE\u03B9\u03BC\u03B7 \u03BC\u03C5\u03BF\u03C7\u03AC\u03BB\u03B1\u03C3\u03B7",
      "\u0392\u03B5\u03BB\u03C4\u03B9\u03C3\u03C4\u03BF\u03C0\u03BF\u03AF\u03B7\u03C3\u03B7: \u03B8\u03AD\u03C3\u03B7, \u03B5\u03BE\u03C9\u03C4\u03B5\u03C1\u03B9\u03BA\u03CC\u03C2 \u03BB\u03B1\u03C1\u03C5\u03B3\u03B3\u03B9\u03BA\u03CC\u03C2 \u03C7\u03B5\u03B9\u03C1\u03B9\u03C3\u03BC\u03CC\u03C2, bougie",
      "\u0388\u03C9\u03C2 3 \u03C0\u03C1\u03BF\u03C3\u03C0\u03AC\u03B8\u03B5\u03B9\u03B5\u03C2 (+1 \u03B1\u03C0\u03CC \u03C0\u03B9\u03BF \u03AD\u03BC\u03C0\u03B5\u03B9\u03C1\u03BF) \u2014 \u03B5\u03C0\u03B9\u03B2\u03B5\u03B2\u03B1\u03AF\u03C9\u03C3\u03B7 \u03BC\u03B5 \u03BA\u03B1\u03C0\u03BD\u03BF\u03B3\u03C1\u03B1\u03C6\u03AF\u03B1",
      "\u0394\u03AE\u03BB\u03C9\u03C3\u03B7 \u03B1\u03C0\u03BF\u03C4\u03C5\u03C7\u03AF\u03B1\u03C2 \u2192 Plan B",
