      "\u0391\u03C0\u03BF\u03C4\u03C5\u03C7\u03AF\u03B1 \u03BF\u03BE\u03C5\u03B3\u03CC\u03BD\u03C9\u03C3\u03B7\u03C2 \u03BC\u03B5\u03C4\u03AC \u03B1\u03C0\u03CC 3 \u2192 Plan C",
      "\u2014 PLAN C: \u039C\u0391\u03A3\u039A\u0391 \u2014",
