      "\u03A4\u03BF\u03BC\u03AE \u2192 \u03C3\u03C4\u03C1\u03BF\u03C6\u03AE \u03BB\u03B5\u03C0\u03AF\u03B4\u03B1\u03C2 \u2192 bougie \u2192 \u0395\u03A4\u03A4 6.0 \u03BC\u03B5 cuff \u2192 \u03B5\u03C0\u03B9\u03B2\u03B5\u03B2\u03B1\u03AF\u03C9\u03C3\u03B7 \u03BA\u03B1\u03C0\u03BD\u03BF\u03B3\u03C1\u03B1\u03C6\u03AF\u03B1\u03C2",
